import{_ as i,o as a,c as e,a2 as n}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Cron Jobs","description":"","frontmatter":{},"headers":[],"relativePath":"app/cronjobs.md","filePath":"app/cronjobs.md"}'),t={name:"app/cronjobs.md"};function r(o,s,h,l,p,d){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="cron-jobs" tabindex="-1">Cron Jobs <a class="header-anchor" href="#cron-jobs" aria-label="Permalink to &quot;Cron Jobs&quot;">​</a></h1><p>Cron jobs run scheduled commands inside your application&#39;s environment — for example clearing caches, sending digests, or pruning data. You define them in <code>.tragwerk/config.xml</code> and Tragwerk runs them on the server in a dedicated scheduler container.</p><h2 id="defining-cron-jobs" tabindex="-1">Defining cron jobs <a class="header-anchor" href="#defining-cron-jobs" aria-label="Permalink to &quot;Defining cron jobs&quot;">​</a></h2><p>Cron jobs live in the XML <code>&lt;crons&gt;</code> block. Each job has a name, a schedule (standard cron expression), and a command. See the configuration reference: <a href="/config/crons">Crons configuration</a>.</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">crons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cron</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cache-clear&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> schedule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0 * * * *&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bin/console cache:clear&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cron</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;digest&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> schedule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0 6 * * *&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bin/console app:send-digest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">crons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="how-it-runs-on-the-server" tabindex="-1">How it runs on the server <a class="header-anchor" href="#how-it-runs-on-the-server" aria-label="Permalink to &quot;How it runs on the server&quot;">​</a></h2><p>For each application Tragwerk starts a <strong>supercronic</strong> sidecar container named <code>{app}-cron</code>. Supercronic is a cron implementation built for containers: it reads the generated crontab, runs each command on schedule inside the app&#39;s runtime, and logs structured (JSON) output.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Supercronic is used instead of the system <code>cron</code> daemon because it logs to stdout in a machine-readable form, runs as a non-root container process, and needs no MTA — which is exactly what Tragwerk needs to capture run history.</p></div><h2 id="run-history-and-live-logs" tabindex="-1">Run history and live logs <a class="header-anchor" href="#run-history-and-live-logs" aria-label="Permalink to &quot;Run history and live logs&quot;">​</a></h2><p>The Cron Jobs view shows three things:</p><ul><li><strong>Definitions</strong> — the jobs declared in your config (name, schedule, command).</li><li><strong>Run history</strong> — the last execution time and result (success/failure) per job.</li><li><strong>Live logs</strong> — output streamed as a job runs.</li></ul><p>Behind the scenes Tragwerk parses the <code>{app}-cron</code> container&#39;s supercronic logs, persists each run (start time, finish time, success flag, captured output), and streams updates so the UI reflects runs live. A run shows as in-progress until its finishing log line is ingested. This happens automatically.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>A job that runs every five minutes:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">crons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cron</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;heartbeat&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> schedule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*/5 * * * *&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bin/console app:heartbeat&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">crons</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>After deployment, open <strong>Cron Jobs</strong>, find <code>heartbeat</code>, and watch its run history populate every five minutes with the last result and log output.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/config/crons">Crons configuration</a></li><li><a href="/app/workers">Workers</a></li><li><a href="/app/logs-containers">Logs &amp; Containers</a></li></ul>`,18)])])}const g=i(t,[["render",r]]);export{k as __pageData,g as default};
